// src/pages/FarmDetail.js
import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../Dashboard.css';
import './FormPage.css'; // Sáŧ­ dáŧĨng lášĄi CSS cho form
import './Manager.css'; // Sáŧ­ dáŧĨng lášĄi CSS cho bášĢng (nášŋu bášĄn cÃģ cÃĄc style bášĢng riÃŠng cho activities)

function FarmDetail() {
  const { farmId } = useParams(); // LášĨy farmId táŧŦ URL
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const role = localStorage.getItem('role'); // LášĨy vai trÃē ngÆ°áŧi dÃđng Äáŧ kiáŧm tra quyáŧn

  const [farm, setFarm] = useState(null);
  const [activities, setActivities] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  // State cho form nháš­p bášĢn ghi theo dÃĩi
  const [activityFormData, setActivityFormData] = useState({
    speciesName: '', // TÃŠn loÃ i - Giáŧ ÄÃĒy sáš― ÄÆ°áŧĢc cháŧn táŧŦ dropdown áŧ Äáš§u trang
    date: '',        // NgÃ y ghi nháš­n
    totalIndividuals: 0, // Táŧng sáŧ cÃĄ tháŧ - GiÃĄ tráŧ nÃ y sáš― khÃīng ÄÆ°áŧĢc nháš­p qua UI form náŧŊa
    currentStatus: { // currentStatus vášŦn ÄÆ°áŧĢc giáŧŊ trong state Äáŧ gáŧ­i lÃŠn backend
      parents: { male: 0, female: 0 },
      otherIndividuals: { male: 0, female: 0, unidentified: 0 }
    },
    increase: {
      parents: { male: 0, female: 0 },
      otherIndividuals: { male: 0, female: 0, unidentified: 0 }
    },
    decrease: {
      parents: { male: 0, female: 0 },
      otherIndividuals: { male: 0, female: 0, unidentified: 0 }
    },
    reasonForChange: '',
    verifiedBy: '', // TrÆ°áŧng nÃ y sáš― khÃīng cÃēn ÄÆ°áŧĢc nháš­p qua UI form náŧŊa
  });

  // HÃ m fetch chi tiášŋt cÆĄ sáŧ gÃĒy nuÃīi vÃ  cÃĄc bášĢn ghi theo dÃĩi
  const fetchFarmDetails = async () => {
    setLoading(true);
    setError('');
    setMessage('');
    try {
      // LášĨy thÃīng tin chi tiášŋt cÆĄ sáŧ nuÃīi
      const resFarm = await axios.get(`http://localhost:10000/api/farms/${farmId}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setFarm(resFarm.data);

      // Nášŋu cÃģ dáŧŊ liáŧu loÃ i, Äáš·t giÃĄ tráŧ máš·c Äáŧnh cho speciesName trong form hoášĄt Äáŧng
      if (resFarm.data.species && resFarm.data.species.length > 0) {
        setActivityFormData(prev => ({
          ...prev,
          speciesName: resFarm.data.species[0].name // Äáš·t loÃ i Äáš§u tiÃŠn lÃ m máš·c Äáŧnh
        }));
      }

      // LášĨy cÃĄc bášĢn ghi theo dÃĩi biášŋn Äáŧng cho cÆĄ sáŧ nÃ y
      const resActivities = await axios.get(`http://localhost:10000/api/farm-activities/${farmId}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setActivities(resActivities.data);

    } catch (err) {
      console.error('Láŧi khi tášĢi chi tiášŋt cÆĄ sáŧ nuÃīi hoáš·c cÃĄc bášĢn ghi theo dÃĩi:', err.response?.data || err.message);
      setError(err.response?.data?.message || 'KhÃīng tháŧ tášĢi chi tiášŋt cÆĄ sáŧ gÃĒy nuÃīi hoáš·c cÃĄc bášĢn ghi theo dÃĩi.');
      // Chuyáŧn hÆ°áŧng nášŋu khÃīng tÃŽm thášĨy hoáš·c khÃīng cÃģ quyáŧn
      if (err.response && (err.response.status === 401 || err.response.status === 403 || err.response.status === 404)) {
        navigate('/admin/farms');
      }
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    console.log("FarmDetail.js: useEffect is running!"); // ThÃŠm console log Äáŧ kiáŧm tra
    if (farmId && token) {
      fetchFarmDetails();
    } else if (!farmId) {
      setError('KhÃīng cÃģ ID cÆĄ sáŧ nuÃīi Äáŧ xem chi tiášŋt.');
      setLoading(false);
    } else if (!token) {
      setError('BášĄn cáš§n ÄÄng nháš­p Äáŧ xem chi tiášŋt cÆĄ sáŧ nuÃīi.');
      setLoading(false);
      navigate('/');
    }
  }, [farmId, token, navigate]); // ThÃŠm navigate vÃ o dependency array

  const handleActivityFormChange = (e) => {
    const { name, value } = e.target;
    let newFormData = { ...activityFormData };

    // Xáŧ­ lÃ― cÃĄc trÆ°áŧng ÄÆĄn giášĢn tráŧąc tiášŋp (speciesName, date, reasonForChange)
    if (['speciesName', 'date', 'reasonForChange'].includes(name)) { // verifiedBy ÄÃĢ báŧ loášĄi báŧ kháŧi ÄÃĒy
      newFormData = {
        ...newFormData,
        [name]: value,
      };
    }
    else {
      // Xáŧ­ lÃ― cÃĄc trÆ°áŧng nested (increase, decrease)
      const [mainField, subField, prop] = name.split('.');
      newFormData = {
        ...newFormData,
        [mainField]: {
          ...newFormData[mainField],
          [subField]: {
            ...newFormData[mainField][subField],
            [prop]: parseInt(value, 10) || 0,
          },
        },
      };
    }
    setActivityFormData(newFormData);
  };

  const handleAddActivity = async (e) => {
    e.preventDefault();
    setMessage('');
    setError('');
    try {
      // ÄášĢm bášĢo farmId ÄÆ°áŧĢc gáŧ­i cÃđng váŧi dáŧŊ liáŧu form
      const dataToSend = {
        ...activityFormData,
        farm: farmId, // LiÃŠn kášŋt bášĢn ghi theo dÃĩi váŧi farmId
      };
      const res = await axios.post(`http://localhost:10000/api/farm-activities`, dataToSend, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setMessage('ThÃŠm bášĢn ghi theo dÃĩi thÃ nh cÃīng!');
      // Cáš­p nháš­t lášĄi danh sÃĄch activities
      setActivities(prevActivities => [...prevActivities, res.data]);
      // Reset form, giáŧŊ lášĄi speciesName nášŋu nÃģ ÄÃĢ ÄÆ°áŧĢc cháŧn áŧ trÃŠn
      setActivityFormData(prev => ({
        ...prev,
        date: '',
        totalIndividuals: 0, // Reset váŧ 0
        currentStatus: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
        increase: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
        decrease: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
        reasonForChange: '',
        verifiedBy: '', // Reset váŧ ráŧng
      }));
    } catch (err) {
      console.error('Láŧi khi thÃŠm bášĢn ghi theo dÃĩi:', err.response?.data || err.message);
      setError(err.response?.data?.message || 'Láŧi khi thÃŠm bášĢn ghi theo dÃĩi.');
    }
  };

  const handleDeleteActivity = async (activityId) => {
    if (window.confirm('BášĄn cÃģ chášŊc chášŊn muáŧn xÃģa bášĢn ghi nÃ y?')) {
      setMessage('');
      setError('');
      try {
        await axios.delete(`http://localhost:10000/api/farm-activities/${activityId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        setMessage('BášĢn ghi ÄÃĢ ÄÆ°áŧĢc xÃģa thÃ nh cÃīng.');
        // Cáš­p nháš­t lášĄi danh sÃĄch activities sau khi xÃģa
        setActivities(prevActivities => prevActivities.filter(act => act._id !== activityId));
      } catch (err) {
        console.error('Láŧi khi xÃģa bášĢn ghi theo dÃĩi:', err.response?.data || err.message);
        setError(err.response?.data?.message || 'Láŧi khi xÃģa bášĢn ghi theo dÃĩi.');
      }
    }
  };


  if (loading) {
    return <div className="form-container"><p>Äang tášĢi dáŧŊ liáŧu...</p></div>;
  }

  if (error) {
    return (
      <div className="form-container">
        <p style={{ color: 'red' }}>Láŧi: {error}</p>
        <button onClick={() => navigate('/admin/farms')}>Quay lášĄi danh sÃĄch</button>
      </div>
    );
  }

  if (!farm) {
    return (
      <div className="form-container">
        <p style={{ color: 'orange' }}>KhÃīng tÃŽm thášĨy thÃīng tin cÆĄ sáŧ gÃĒy nuÃīi.</p>
        <button onClick={() => navigate('/admin/farms')}>Quay lášĄi danh sÃĄch</button>
      </div>
    );
  }

  return (
    <div className="form-container">
      {/* ThÃŠm CSS tÃđy cháŧnh vÃ o ÄÃĒy */}
      <style>
        {`
        .form-section-wrapper {
          flex: 1; /* ÄášĢm bášĢo cÃĄc pháš§n TÄng ÄÃ n/GiášĢm ÄÃ n chia Äáŧu khÃīng gian */
          min-width: 300px; /* NgÄn khÃīng cho chÃšng quÃĄ nháŧ trÃŠn mÃ n hÃŽnh hášđp */
          padding: 10px; /* ThÃŠm padding Äáŧ tášĄo khoášĢng cÃĄch giáŧŊa cÃĄc wrapper */
          box-sizing: border-box; /* ÄášĢm bášĢo padding khÃīng lÃ m tÄng kÃ­ch thÆ°áŧc táŧng tháŧ */
        }

        .form-section-row {
          display: flex;
          gap: 20px; /* TÄng khoášĢng cÃĄch giáŧŊa cÃĄc input trong cÃđng máŧt hÃ ng */
          margin-bottom: 5px; /* ÄÃĢ giášĢm khoášĢng cÃĄch giáŧŊa cÃĄc dÃēng */
          align-items: center;
        }

        /* Äiáŧu cháŧnh cho input trong form-group Äáŧ chÃšng khÃīng báŧ quÃĄ nháŧ */
        .form-group input[type="number"] {
          width: 100%; /* ÄášĢm bášĢo input chiášŋm hášŋt chiáŧu ráŧng cÃģ tháŧ */
          box-sizing: border-box; /* Bao gáŧm padding vÃ  border vÃ o width */
        }
        `}
      </style>

      <h2>ðïļ Sáŧ nuÃīi: {farm.tenCoSo}</h2>
      
      {/* ÄÃĢ thay Äáŧi Äáŧ TÃŠn cÆĄ sáŧ, Äáŧa cháŧ vÃ  TÃŠn loÃ i ngang hÃ ng */}
      <div className="form-grid"> {/* Sáŧ­ dáŧĨng form-grid Äáŧ tášĄo cÃĄc cáŧt */}
        <div className="detail-group">
          <strong>TÃŠn cÆĄ sáŧ:</strong> <p>{farm.tenCoSo}</p>
        </div>
        <div className="detail-group">
          <strong>Äáŧa cháŧ:</strong> <p>{farm.diaChi}</p>
        </div>
        <div className="form-group detail-group"> {/* ÄÃĢ di chuyáŧn Ãī cháŧn TÃŠn loÃ i lÃŠn ÄÃĒy */}
          <label>TÃŠn loÃ i:</label>
          <select
            name="speciesName"
            value={activityFormData.speciesName}
            onChange={handleActivityFormChange}
            required
          >
            <option value="">-- Cháŧn loÃ i --</option>
            {farm.species && farm.species.map((species, index) => (
              <option key={index} value={species.name}>
                {species.name}
              </option>
            ))}
          </select>
        </div>
      </div>

      <h3>ThÃŠm bášĢn ghi theo dÃĩi máŧi:</h3>
      {message && <div className="success-message">{message}</div>}
      {error && <div className="error-message">{error}</div>}
      <form onSubmit={handleAddActivity} className="modern-form">
        <div className="form-grid"> {/* Sáŧ­ dáŧĨng form-grid Äáŧ sášŊp xášŋp cÃĄc trÆ°áŧng cáŧ§a form */}
          {/* TrÆ°áŧng TÃŠn loÃ i ÄÃĢ ÄÆ°áŧĢc di chuyáŧn lÃŠn trÃŠn */}
          <div className="form-group">
            <label>NgÃ y ghi nháš­n:</label>
            <input
              type="date"
              name="date"
              value={activityFormData.date}
              onChange={handleActivityFormChange}
              required
            />
          </div>
          {/* ÄÃĢ di chuyáŧn trÆ°áŧng NguyÃŠn nhÃĒn biášŋn Äáŧng lÃŠn ÄÃĒy */}
          <div className="form-group">
            <label>NguyÃŠn nhÃĒn biášŋn Äáŧng:</label>
            <input
              type="text"
              name="reasonForChange"
              value={activityFormData.reasonForChange}
              onChange={handleActivityFormChange}
            />
          </div>
        </div>

        {/* ÄÃĢ nhÃģm TÄng ÄÃ n vÃ  GiášĢm ÄÃ n vÃ o cÃđng máŧt form-grid Äáŧ chÃšng ngang hÃ ng */}
        <div className="form-grid">
          <div className="form-section-wrapper"> {/* Wrapper cho nhÃģm TÄng ÄÃ n */}
            <h4>TÄng ÄÃ n:</h4>
            <div className="form-grid nested-grid">
              <div className="form-section">
                <h5>Báŧ mášđ:</h5>
                <div className="form-section-row">
                  <div className="form-group">
                    <label>Äáŧąc:</label>
                    <input type="number" name="increase.parents.male" value={activityFormData.increase.parents.male} onChange={handleActivityFormChange} min="0" />
                  </div>
                  <div className="form-group">
                    <label>CÃĄi:</label>
                    <input type="number" name="increase.parents.female" value={activityFormData.increase.parents.female} onChange={handleActivityFormChange} min="0" />
                  </div>
                </div>
              </div>
              <div className="form-section">
                <h5>CÃĄ tháŧ khÃĄc:</h5>
                <div className="form-section-row">
                  <div className="form-group">
                    <label>Äáŧąc:</label>
                    <input type="number" name="increase.otherIndividuals.male" value={activityFormData.increase.otherIndividuals.male} onChange={handleActivityFormChange} min="0" />
                  </div>
                  <div className="form-group">
                    <label>CÃĄi:</label>
                    <input type="number" name="increase.otherIndividuals.female" value={activityFormData.increase.otherIndividuals.female} onChange={handleActivityFormChange} min="0" />
                  </div>
                  <div className="form-group">
                    <label>KhÃīng rÃĩ:</label>
                    <input type="number" name="increase.otherIndividuals.unidentified" value={activityFormData.increase.otherIndividuals.unidentified} onChange={handleActivityFormChange} min="0" />
                  </div>
                </div>
              </div>
            </div>
          </div>

          <div className="form-section-wrapper"> {/* Wrapper cho nhÃģm GiášĢm ÄÃ n */}
            <h4>GiášĢm ÄÃ n:</h4>
            <div className="form-grid nested-grid">
              <div className="form-section">
                <h5>Báŧ mášđ:</h5>
                <div className="form-section-row">
                  <div className="form-group">
                    <label>Äáŧąc:</label>
                    <input type="number" name="decrease.parents.male" value={activityFormData.decrease.parents.male} onChange={handleActivityFormChange} min="0" />
                  </div>
                  <div className="form-group">
                    <label>CÃĄi:</label>
                    <input type="number" name="decrease.parents.female" value={activityFormData.decrease.parents.female} onChange={handleActivityFormChange} min="0" />
                  </div>
                </div>
              </div>
              <div className="form-section">
                <h5>CÃĄ tháŧ khÃĄc:</h5>
                <div className="form-section-row">
                  <div className="form-group">
                    <label>Äáŧąc:</label>
                    <input type="number" name="decrease.otherIndividuals.male" value={activityFormData.decrease.otherIndividuals.male} onChange={handleActivityFormChange} min="0" />
                  </div>
                  <div className="form-group">
                    <label>CÃĄi:</label>
